<?php
 namespace WPAICG\Utils; if (!defined('ABSPATH')) { exit; } class AIPKit_Identifier_Utils { public static function generate_chat_context_identifier( ?int $user_id, ?string $session_id, string $prefix = 'aipkit_ctx', int $random_length = 8 ): string { $identifier_base = ''; if ($user_id && $user_id > 0) { $identifier_base = "u{$user_id}"; } elseif (!empty($session_id)) { $sanitized_session_id = preg_replace('/[^a-zA-Z0-9]/', '', $session_id); $sanitized_session_id = substr($sanitized_session_id, 0, 20); $identifier_base = "g_{$sanitized_session_id}"; } else { $identifier_base = "unk"; } $timestamp = time(); $random_suffix_chars = '0123456789abcdefghijklmnopqrstuvwxyz'; $random_suffix = ''; for ($i = 0; $i < $random_length; $i++) { $random_suffix .= $random_suffix_chars[wp_rand(0, strlen($random_suffix_chars) - 1)]; } $raw_identifier = strtolower("{$prefix}_{$identifier_base}_{$timestamp}_{$random_suffix}"); $final_identifier = sanitize_key($raw_identifier); return $final_identifier; } }